import{_ as l,o as e,c as i,a2 as a}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"🤖 台灣機器人供應鏈機會深度分析","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/機器人研究/機器人研究_台股供應鏈機會.md","filePath":"Deep32Q知識庫/產業洞察/機器人研究/機器人研究_台股供應鏈機會.md"}'),r={name:"Deep32Q知識庫/產業洞察/機器人研究/機器人研究_台股供應鏈機會.md"};function n(s,t,o,d,g,h){return e(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="🤖-台灣機器人供應鏈機會深度分析" tabindex="-1">🤖 台灣機器人供應鏈機會深度分析 <a class="header-anchor" href="#🤖-台灣機器人供應鏈機會深度分析" aria-label="Permalink to &quot;🤖 台灣機器人供應鏈機會深度分析&quot;">​</a></h1><blockquote><p><strong>最後更新</strong>：2026-06-11 <strong>研究範疇</strong>：台灣在機器人全球供應鏈中的定位、台廠技術實力與客戶結構、成長能見度</p></blockquote><hr><h2 id="一、台灣在機器人供應鏈的戰略定位" tabindex="-1">一、台灣在機器人供應鏈的戰略定位 <a class="header-anchor" href="#一、台灣在機器人供應鏈的戰略定位" aria-label="Permalink to &quot;一、台灣在機器人供應鏈的戰略定位&quot;">​</a></h2><p>台灣在機器人產業中扮演的是 <strong>「精密機械硬體重鎮」</strong> 的角色，尤其集中在：</p><table tabindex="0"><thead><tr><th style="text-align:left;">環節</th><th style="text-align:left;">台灣實力</th><th style="text-align:right;">全球定位</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>精密傳動元件</strong></td><td style="text-align:left;">🟢 世界級</td><td style="text-align:right;">上銀全球前三大線性傳動廠；直得全球第三大微型線性滑軌</td></tr><tr><td style="text-align:left;"><strong>伺服馬達</strong></td><td style="text-align:left;">🟡 中上</td><td style="text-align:right;">台達電中低階伺服市占大，高階尚難敵 Yaskawa/Fanuc</td></tr><tr><td style="text-align:left;"><strong>控制器</strong></td><td style="text-align:left;">🟡 利基市場</td><td style="text-align:right;">新代 PC-Based 控制器在中國高階市場持續擴大</td></tr><tr><td style="text-align:left;"><strong>AI 視覺/感測</strong></td><td style="text-align:left;">🟢 具競爭力</td><td style="text-align:right;">所羅門 AI 視覺辨識技術為國際級</td></tr><tr><td style="text-align:left;"><strong>協作機器人</strong></td><td style="text-align:left;">🟢 全球 Top 5</td><td style="text-align:right;">達明機器人全球協作機器人市占 Top 5</td></tr><tr><td style="text-align:left;"><strong>AMR/AGV</strong></td><td style="text-align:left;">🟡 區域強勢</td><td style="text-align:right;">盟立、迅得、廣運在台/中市場有競爭力</td></tr><tr><td style="text-align:left;"><strong>OEM 代工</strong></td><td style="text-align:left;">🟢 世界級</td><td style="text-align:right;">鴻海、廣達大規模精密製造能力，是 Tesla/Optimus 潛在代工夥伴</td></tr><tr><td style="text-align:left;"><strong>邊緣運算/AI 晶片</strong></td><td style="text-align:left;">🟡 間接參與</td><td style="text-align:right;">台積電為 NVIDIA/Jetson 晶圓代工；研華、宜鼎提供邊緣運算硬體</td></tr></tbody></table><blockquote><p>💡 <strong>台灣的「微笑曲線」位置</strong>：</p><ul><li>左端高利潤區：精密傳動、AI 視覺、控制器（台廠有實力）</li><li>右端高利潤區：系統整合、服務訂閱（台廠相對弱勢）</li><li>谷底低利潤區：純硬體組裝代工（台廠實力強但利潤薄）</li></ul></blockquote><hr><h2 id="二、台廠逐一深入分析" tabindex="-1">二、台廠逐一深入分析 <a class="header-anchor" href="#二、台廠逐一深入分析" aria-label="Permalink to &quot;二、台廠逐一深入分析&quot;">​</a></h2><h3 id="🟢-上銀科技-2049" tabindex="-1">🟢 上銀科技（2049） <a class="header-anchor" href="#🟢-上銀科技-2049" aria-label="Permalink to &quot;🟢 上銀科技（2049）&quot;">​</a></h3><p><strong>核心產品</strong>：線性滑軌、滾珠螺桿、工業機器人手臂、諧波減速機（開發中）</p><p><strong>供應鏈角色</strong>：</p><ul><li>全球最大的線性傳動元件供應商之一，與 THK (日)、NSK (日) 並列前三大</li><li>產品為工業機器人「關節」的基礎傳動件，所有機器人品牌（ABB、Fanuc、KUKA）在亞洲產線幾乎都會用到</li><li>開發人形機器人專用諧波減速機 + 交叉滾柱軸承，與大銀微系統(4576)合作推出「整合型關節模組」</li></ul><p><strong>成長動能</strong>：</p><ul><li>自動化產線資本支出重啟，訂單能見度 2-3 季</li><li>2025 年自行開發物流機器人，2026 年小量產，與美國 Dexterity 合作 AI 手臂「Mech」</li><li>機器人營收目標：2026 年佔總營收 10%+</li></ul><p><strong>風險</strong>：</p><ul><li>傳統工具機/自動化景氣循環影響本業波動</li><li>諧波減速機量產時程不確定性</li><li>2025Q3 營業利益率僅 6.8%，本業獲利仍在低檔</li></ul><hr><h3 id="🟢-大銀微系統-4576" tabindex="-1">🟢 大銀微系統（4576） <a class="header-anchor" href="#🟢-大銀微系統-4576" aria-label="Permalink to &quot;🟢 大銀微系統（4576）&quot;">​</a></h3><p><strong>核心產品</strong>：精密伺服馬達、力矩馬達、直驅系統、關節模組</p><p><strong>供應鏈角色</strong>：</p><ul><li>上銀子公司，專注精密電機技術</li><li>與上銀合作開發人形機器人整合型關節模組：減速機 + 馬達 + 編碼器 + 驅動器於一體</li><li>潛在客戶：Tesla Optimus、Figure AI</li></ul><p><strong>成長動能</strong>：</p><ul><li>跟上銀連動，但更具機器人直接曝險</li><li>晶圓機器人（Wafer Robot）用於半導體無塵室，受惠先進製程擴廠</li></ul><hr><h3 id="🟢-直得-1597" tabindex="-1">🟢 直得（1597） <a class="header-anchor" href="#🟢-直得-1597" aria-label="Permalink to &quot;🟢 直得（1597）&quot;">​</a></h3><p><strong>核心產品</strong>：微型線性滑軌、線性馬達、驅動器、六軸機械手臂、人形機器人關節模組</p><p><strong>供應鏈角色</strong>：</p><ul><li>全球第三大微型線性滑軌廠（前兩大為 THK/NSK）</li><li>正從傳動元件向機器人本體延伸：開發六軸機械手臂與人形機器人關節模組</li></ul><p><strong>成長動能</strong>：</p><ul><li>2026年4月起對驅動器、線性滑軌與線性馬達全面調漲售價</li><li>半導體 CPO 設備需求增加，接單能見度延長 2-3 個月</li><li>3月營收月增 13.38%、年增 38.54%（2026 數據）</li></ul><hr><h3 id="🟡-全球傳動-4540" tabindex="-1">🟡 全球傳動（4540） <a class="header-anchor" href="#🟡-全球傳動-4540" aria-label="Permalink to &quot;🟡 全球傳動（4540）&quot;">​</a></h3><p><strong>核心產品</strong>：滾珠螺桿、線性滑軌、滾珠花鍵（自有品牌 TBI MOTION）</p><p><strong>供應鏈角色</strong>：</p><ul><li>中低階精密傳動元件，定位與上銀部分重疊但規模較小</li><li>中國市場依賴度高（約佔營收 40%）</li></ul><p><strong>成長動能</strong>：</p><ul><li>中國市場需求回溫，3月營收創 10 年同期新高</li><li>4月起全品項調漲約 10%，毛利率改善</li><li>機器人需求傳導至傳動元件，屬於間接受益</li></ul><hr><h3 id="🟢-台達電-2308" tabindex="-1">🟢 台達電（2308） <a class="header-anchor" href="#🟢-台達電-2308" aria-label="Permalink to &quot;🟢 台達電（2308）&quot;">​</a></h3><p><strong>核心產品</strong>：伺服馬達、工業電源、散熱、工業自動化解決方案</p><p><strong>供應鏈角色</strong>：</p><ul><li>台灣最大工業自動化廠商，產品線涵蓋伺服、驅動器、PLC、SCADA</li><li>正積極開發協作型機器人與人形機器人專用馬達</li><li>在 AI 伺服器電源 + 散熱領域世界級地位</li></ul><p><strong>成長動能</strong>：</p><ul><li>工業自動化部門受惠全球製造業回流</li><li>機器人市場可望成為下一個營收動能</li><li>邊緣運算電源解決方案（搭配 NVIDIA Jetson）</li></ul><hr><h3 id="🟢-所羅門-2359" tabindex="-1">🟢 所羅門（2359） <a class="header-anchor" href="#🟢-所羅門-2359" aria-label="Permalink to &quot;🟢 所羅門（2359）&quot;">​</a></h3><p><strong>核心產品</strong>：AI 視覺辨識（Solomon Vision）、3D 感測、機器人視覺引導</p><p><strong>供應鏈角色</strong>：</p><ul><li>台灣 AI 視覺標竿，技術與 Cognex (美)、Keyence (日) 在特定領域可競爭</li><li>與 NVIDIA 合作 Isaac 平台，提供機器人「雙眼」</li><li>產品整合到 ABB、Fanuc、Universal Robots 等品牌的視覺方案中</li></ul><p><strong>成長動能</strong>：</p><ul><li>全球機器人導入視覺為剛需（Bin Picking、品質檢測、定位引導）</li><li>AI 視覺軟體毛利高，且具重複性授權收入</li><li>半導體製程中的 AI 視覺檢測需求同步成長</li></ul><hr><h3 id="🟢-新代-7750" tabindex="-1">🟢 新代（7750） <a class="header-anchor" href="#🟢-新代-7750" aria-label="Permalink to &quot;🟢 新代（7750）&quot;">​</a></h3><p><strong>核心產品</strong>：PC-Based 工具機控制器、機器人控制器、AI 視覺整合</p><p><strong>供應鏈角色</strong>：</p><ul><li>台灣工具機控制器龍頭（PC-Based 架構）</li><li>正在從工具機控制器跨入機器人控制器領域</li><li>在中國高階控制器市場市佔持續擴大</li></ul><p><strong>成長動能</strong>：</p><ul><li>蘇州二廠擴建（Q3 啟用），規模為一廠兩倍</li><li>法人估 2026 年營收年增兩位數，EPS 35.12 元，毛利率穩站 45%</li><li>結合 AI 視覺打造智慧機器人「大腦」</li></ul><hr><h3 id="🟢-信邦-3023" tabindex="-1">🟢 信邦（3023） <a class="header-anchor" href="#🟢-信邦-3023" aria-label="Permalink to &quot;🟢 信邦（3023）&quot;">​</a></h3><p><strong>核心產品</strong>：線束、連接器、機內解決方案（完整電源+訊號傳輸）</p><p><strong>供應鏈角色</strong>：</p><ul><li>與美國前三大的人形機器人大廠深度合作</li><li>從研發階段便協助設計全套機內解決方案，為該領域 <strong>單一供應商</strong></li><li>產品包含整機的電源訊號傳輸與複雜線束走線</li></ul><p><strong>成長動能</strong>：</p><ul><li>美系客戶預計 2026 年規模量產，出貨量達 1 萬套</li><li>機器人業務營收貢獻預計 2027 年進入顯著成長期</li><li>連接器/線束為機器人必備零件，且具客製化高黏著度</li></ul><hr><h3 id="🟡-盟立-2464" tabindex="-1">🟡 盟立（2464） <a class="header-anchor" href="#🟡-盟立-2464" aria-label="Permalink to &quot;🟡 盟立（2464）&quot;">​</a></h3><p><strong>核心產品</strong>：自動化倉儲/物流系統、AGV/AMR、天車（OHT）</p><p><strong>供應鏈角色</strong>：</p><ul><li>台灣自動化物流設備領導廠</li><li>與和大(1536)合資盟英科技，專攻 AI 人形機器人核心零件</li><li>與零組件廠精確合資生產機器人金屬壓鑄件 + 整機組裝</li><li>參與鞍新盟聯盟（新代、金鞍機械）發展機器人</li></ul><p><strong>成長動能</strong>：</p><ul><li>半導體廠天車 + AMR 需求隨先進製程擴廠成長</li><li>人形機器人轉投資屬早期布局，尚無顯著營收貢獻</li></ul><hr><h3 id="🟢-廣明光電-6188-達明機器人" tabindex="-1">🟢 廣明光電（6188）／達明機器人 <a class="header-anchor" href="#🟢-廣明光電-6188-達明機器人" aria-label="Permalink to &quot;🟢 廣明光電（6188）／達明機器人&quot;">​</a></h3><p><strong>核心產品</strong>：協作機器人手臂（TM Robot）、智慧視覺整合</p><p><strong>供應鏈角色</strong>：</p><ul><li>達明機器人為廣明子公司，2025 年全球協作機器人市占率 Top 5</li><li>全球少數能將 AI 視覺內建於機械手臂的本土品牌</li><li>客戶涵蓋電子組裝、汽車零組件、食品包裝等領域</li></ul><p><strong>成長動能</strong>：</p><ul><li>協作機器人市場 CAGR 20.5%（2023-2028），屬高速成長賽道</li><li>達明 TM Robot 在亞洲市場具品牌知名度</li></ul><hr><h3 id="🟡-鴻海-2317" tabindex="-1">🟡 鴻海（2317） <a class="header-anchor" href="#🟡-鴻海-2317" aria-label="Permalink to &quot;🟡 鴻海（2317）&quot;">​</a></h3><p><strong>核心產品</strong>：機器人 OEM 代工、自有品牌機器人（FoxBot）</p><p><strong>供應鏈角色</strong>：</p><ul><li>大規模精密製造能力，是 Tesla/Optimus、Figure AI 等品牌潛在代工夥伴</li><li>生產自有品牌工業機器人（FoxBot）用於自家工廠產線</li><li>鴻海研究院開發機器人 AI 軟體與感知技術</li></ul><p><strong>成長動能</strong>：</p><ul><li>若接到人形機器人量產代工訂單，將是巨大營收動能</li><li>目前尚無確認客戶，仍需觀察</li></ul><hr><h3 id="🟡-研華-2395" tabindex="-1">🟡 研華（2395） <a class="header-anchor" href="#🟡-研華-2395" aria-label="Permalink to &quot;🟡 研華（2395）&quot;">​</a></h3><p><strong>核心產品</strong>：工業電腦、邊緣運算平台、機器控制器</p><p><strong>供應鏈角色</strong>：</p><ul><li>NVIDIA Isaac 合作夥伴，提供機器人邊緣運算硬體</li><li>工業物聯網平台可作為 AMR 調度中心</li></ul><hr><h3 id="其他值得關注" tabindex="-1">其他值得關注 <a class="header-anchor" href="#其他值得關注" aria-label="Permalink to &quot;其他值得關注&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">股號</th><th style="text-align:left;">公司</th><th style="text-align:right;">供應鏈角色</th><th style="text-align:left;">備註</th></tr></thead><tbody><tr><td style="text-align:center;">6205</td><td style="text-align:left;">詮欣</td><td style="text-align:right;">連接器/線束</td><td style="text-align:left;">次要供應商</td></tr><tr><td style="text-align:center;">2392</td><td style="text-align:left;">正崴</td><td style="text-align:right;">連接器/線束</td><td style="text-align:left;">間接受惠</td></tr><tr><td style="text-align:center;">6438</td><td style="text-align:left;">迅得</td><td style="text-align:right;">半導體 AMR/自動化</td><td style="text-align:left;">受惠半導體擴廠</td></tr><tr><td style="text-align:center;">6125</td><td style="text-align:left;">廣運</td><td style="text-align:right;">AMR/自動化物流</td><td style="text-align:left;">系統整合商</td></tr><tr><td style="text-align:center;">8374</td><td style="text-align:left;">羅昇</td><td style="text-align:right;">機器人代工(亞馬遜搬運)</td><td style="text-align:left;">接單型</td></tr><tr><td style="text-align:center;">5289</td><td style="text-align:left;">宜鼎</td><td style="text-align:right;">邊緣運算/AI 記憶體模組</td><td style="text-align:left;">間接</td></tr></tbody></table><hr><h2 id="三、台廠受益程度矩陣" tabindex="-1">三、台廠受益程度矩陣 <a class="header-anchor" href="#三、台廠受益程度矩陣" aria-label="Permalink to &quot;三、台廠受益程度矩陣&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">公司</th><th style="text-align:center;">受益程度</th><th style="text-align:center;">機器人營收佔比</th><th style="text-align:center;">技術壁壘</th><th style="text-align:center;">時間維度</th></tr></thead><tbody><tr><td style="text-align:left;">上銀(2049)</td><td style="text-align:center;">🔴🔴🔴🔴🟡</td><td style="text-align:center;">~10% (2026目標)</td><td style="text-align:center;">高</td><td style="text-align:center;">現在進行式</td></tr><tr><td style="text-align:left;">直得(1597)</td><td style="text-align:center;">🔴🔴🔴🟡</td><td style="text-align:center;">中等</td><td style="text-align:center;">中</td><td style="text-align:center;">現在進行式</td></tr><tr><td style="text-align:left;">信邦(3023)</td><td style="text-align:center;">🔴🔴🔴🔴</td><td style="text-align:center;">2027 放量</td><td style="text-align:center;">中高</td><td style="text-align:center;">2026-27 放量</td></tr><tr><td style="text-align:left;">台達電(2308)</td><td style="text-align:center;">🔴🔴🔴</td><td style="text-align:center;">低</td><td style="text-align:center;">高</td><td style="text-align:center;">長期布局</td></tr><tr><td style="text-align:left;">所羅門(2359)</td><td style="text-align:center;">🔴🔴🔴</td><td style="text-align:center;">中等</td><td style="text-align:center;">中高</td><td style="text-align:center;">現在進行式</td></tr><tr><td style="text-align:left;">新代(7750)</td><td style="text-align:center;">🔴🔴🟡</td><td style="text-align:center;">低~中</td><td style="text-align:center;">中</td><td style="text-align:center;">成長期</td></tr><tr><td style="text-align:left;">達明機器人</td><td style="text-align:center;">🔴🔴🔴</td><td style="text-align:center;">高 (子公司)</td><td style="text-align:center;">中高</td><td style="text-align:center;">現在進行式</td></tr><tr><td style="text-align:left;">盟立(2464)</td><td style="text-align:center;">🔴🔴</td><td style="text-align:center;">低</td><td style="text-align:center;">中</td><td style="text-align:center;">早期布局</td></tr><tr><td style="text-align:left;">鴻海(2317)</td><td style="text-align:center;">🔴🟡</td><td style="text-align:center;">極低</td><td style="text-align:center;">中高 (代工)</td><td style="text-align:center;">觀察期</td></tr></tbody></table><hr><h2 id="四、總結-台灣的機器人優勢與劣勢" tabindex="-1">四、總結：台灣的機器人優勢與劣勢 <a class="header-anchor" href="#四、總結-台灣的機器人優勢與劣勢" aria-label="Permalink to &quot;四、總結：台灣的機器人優勢與劣勢&quot;">​</a></h2><h3 id="🟢-優勢" tabindex="-1">🟢 優勢 <a class="header-anchor" href="#🟢-優勢" aria-label="Permalink to &quot;🟢 優勢&quot;">​</a></h3><ol><li><strong>精密機械底蘊深厚</strong>：上銀、直得在傳動元件已是世界級，不可取代性高</li><li><strong>半導體+電子製造的溢出效應</strong>：台積電、鴻海的生態系為機器人提供邊緣運算晶片、精密代工能力</li><li><strong>少量多樣的柔性製造</strong>：台灣電子業高度彈性，適合協作型機器人需求</li><li><strong>AI 視覺利基</strong>：所羅門的視覺辨識已獲國際機器人品牌採用</li></ol><h3 id="🔴-弱點" tabindex="-1">🔴 弱點 <a class="header-anchor" href="#🔴-弱點" aria-label="Permalink to &quot;🔴 弱點&quot;">​</a></h3><ol><li><strong>缺乏龍頭品牌</strong>：沒有 ABB、Fanuc 層級的機器人本體品牌</li><li><strong>減速機自製不足</strong>：最高壁壘的諧波/RV 減速機仍嚴重依賴日廠</li><li><strong>軟體/AI 層相對薄弱</strong>：控制系統、VLA 模型、模擬平台主要由美國/中國主導</li><li><strong>人形機器人曝險有限</strong>：多數台廠仍以傳統工業機器人/傳動元件為主，人形機器人布局尚在早期</li></ol><h3 id="📍-最值得關注的策略焦點" tabindex="-1">📍 最值得關注的策略焦點 <a class="header-anchor" href="#📍-最值得關注的策略焦點" aria-label="Permalink to &quot;📍 最值得關注的策略焦點&quot;">​</a></h3><ul><li><strong>短中期（1-2年）</strong>：直得、上銀、信邦 — 訂單能見度與營收成長最明確</li><li><strong>中期（2-3年）</strong>：所羅門、新代 — AI 視覺與控制器的軟體附加價值持續提升</li><li><strong>長期觀察</strong>：鴻海是否接到人形機器人代工大單、台達電是否推出自有品牌機器人</li></ul><hr><h2 id="五、資料來源" tabindex="-1">五、資料來源 <a class="header-anchor" href="#五、資料來源" aria-label="Permalink to &quot;五、資料來源&quot;">​</a></h2><ul><li>CMoney，《2026機器人概念股》</li><li>股感，《機器人概念股正火燙》</li><li>TEJ，《認識機器人產業》</li><li>Digitimes, Taiwan robotics supply chain posts strong 1Q26 gains</li><li>永豐金證券，Computex 2026 亮點</li><li>Taiwan News, Hiwin to launch production of logistics robots by 2026</li><li>BofA Institute, Humanoid Robots 101</li><li>Morgan Stanley, The Humanoid 100</li></ul>',109)])])}const c=l(r,[["render",n]]);export{u as __pageData,c as default};
